 51→  stdout?: string;
 52→  stderr?: string;
 53→  error?: Error;
 54→}) {
 55→  const proc = new EventEmitter() as ReturnType<typeof spawn>;
 56→  const stdoutEmitter = new EventEmitter();
 57→  const stderrEmitter = new EventEmitter();
 58→  (proc as unknown as Record<string, unknown>).stdout = stdoutEmitter;
 59→  (proc as unknown as Record<string, unknown>).stderr = stderrEmitter;
 60→  (proc as unknown as Record<string, unknown>).pid = 12345;
 61→  (proc as unknown as Record<string, unknown>).killed = false;
 62→  (proc as unknown as Record<string, unknown>).kill = vi.fn();
 63→
 64→  // Schedule async emission of data and close events
 65→  queueMicrotask(() => {
 66→    if (opts.stdout) {
 67→      stdoutEmitter.emit("data", Buffer.from(opts.stdout));
 68→    }
 69→    if (opts.stderr) {
 70→      stderrEmitter.emit("data", Buffer.from(opts.stderr));
 71→    }
 72→    if (opts.error) {
 73→      proc.emit("error", opts.error);
 74→    } else {
