100→    });
101→
102→    const { createServer } = await import("./server.js");
103→    createServerFn = createServer;
104→    const { Client } =
105→      await import("@modelcontextprotocol/sdk/client/index.js");
106→    const { InMemoryTransport } =
107→      await import("@modelcontextprotocol/sdk/inMemory.js");
108→
109→    const server = createServer("1.0.0-test");
110→    const clientInstance = new Client({
111→      name: "test-client",
